query JobAuthCheck($id: ID!) {
        jobAuthDetails(id: $id) { buyer { enterprise } }
      }

query JobAuthBuyer($id: ID!) {
        jobAuthDetails(id: $id) {
          buyer {
            enterprise
            isPaymentMethodVerified
            info {
              company { companyId contractDate isEDCReplicated name profile { industry size } }
              location { city country countryTimezone }
              stats {
                score feedbackCount totalAssignments hoursCount
                totalCharges { amount } totalJobsWithHires activeAssignmentsCount
              }
            }
          }
        }
      }

query JobAuthFull($id: ID!) {
        jobAuthDetails(id: $id) {
          buyer {
            enterprise
            isPaymentMethodVerified
            info {
              company { companyId contractDate isEDCReplicated name profile { industry size } }
              location { city country countryTimezone }
              stats { score feedbackCount totalAssignments totalCharges { amount } activeAssignmentsCount totalJobsWithHires }
            }
            workHistory {
              contractorInfo { contractorName }
              jobInfo { title type }
              startDate endDate status totalCharge
              feedback { score comment }
            }
          }
          opening {
            job {
              info { title }
              category { name }
              categoryGroup { name }
            }
          }
          hiredApplicantNames
        }
      }

query {
      organization { id type legacyType flag { client vendor agency individual } }
      companySelector {
        items { organizationId title typeTitle organizationType monetizedTitle }
      }
    }
